import{_ as s,o as i,c as e,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Android 应用","description":"","frontmatter":{"read_when":["配对或重新连接 Android 节点","调试 Android Gateway 网关发现或认证","验证跨客户端的聊天历史一致性"],"summary":"Android 应用（节点）：连接操作手册 + Canvas/Chat/Camera","title":"Android 应用","x-i18n":{"generated_at":"2026-02-03T07:51:34Z","model":"claude-opus-4-5","provider":"pi","source_hash":"9cd02f12065ce2bc483379c9afd7537489d9076094f4a412cf9f21ccc47f0e38","source_path":"platforms/android.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/android.md","filePath":"zh-CN/platforms/android.md","lastUpdated":1771906665000}'),t={name:"zh-CN/platforms/android.md"};function l(d,a,o,h,p,r){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="android-应用-节点" tabindex="-1"><a class="header-anchor" href="#android-应用-节点">#</a> Android 应用（节点）</h1><h2 id="支持概览" tabindex="-1"><a class="header-anchor" href="#支持概览">#</a> 支持概览</h2><ul><li>角色：配套节点应用（Android 不托管 Gateway 网关）。</li><li>需要 Gateway 网关：是（在 macOS、Linux 或通过 WSL2 的 Windows 上运行）。</li><li>安装：<a href="/docs/start/getting-started">入门指南</a> + <a href="/docs/gateway/pairing">配对</a>。</li><li>Gateway 网关：<a href="/docs/gateway/index">操作手册</a> + <a href="/docs/gateway/configuration">配置</a>。 <ul><li>协议：<a href="/docs/gateway/protocol">Gateway 网关协议</a>（节点 + 控制平面）。</li></ul></li></ul><h2 id="系统控制" tabindex="-1"><a class="header-anchor" href="#系统控制">#</a> 系统控制</h2><p>系统控制（launchd/systemd）位于 Gateway 网关主机上。参见 <a href="/docs/gateway/index">Gateway 网关</a>。</p><h2 id="连接操作手册" tabindex="-1"><a class="header-anchor" href="#连接操作手册">#</a> 连接操作手册</h2><p>Android 节点应用 ⇄（mDNS/NSD + WebSocket）⇄ <strong>Gateway 网关</strong></p><p>Android 直接连接到 Gateway 网关 WebSocket（默认 <code>ws://&lt;host&gt;:18789</code>）并使用 Gateway 网关拥有的配对。</p><h3 id="前置条件" tabindex="-1"><a class="header-anchor" href="#前置条件">#</a> 前置条件</h3><ul><li>你可以在&quot;主&quot;机器上运行 Gateway 网关。</li><li>Android 设备/模拟器可以访问 Gateway 网关 WebSocket： <ul><li>使用 mDNS/NSD 的同一局域网，<strong>或</strong></li><li>使用 Wide-Area Bonjour / unicast DNS-SD 的同一 Tailscale tailnet（见下文），<strong>或</strong></li><li>手动 Gateway 网关主机/端口（回退方案）</li></ul></li><li>你可以在 Gateway 网关机器上运行 CLI（<code>opensoul</code>）（或通过 SSH）。</li></ul><h3 id="_1-启动-gateway-网关" tabindex="-1"><a class="header-anchor" href="#_1-启动-gateway-网关">#</a> 1）启动 Gateway 网关</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在日志中确认你看到类似内容：</p><ul><li><code>listening on ws://0.0.0.0:18789</code></li></ul><p>对于仅 tailnet 设置（推荐用于维也纳 ⇄ 伦敦），将 Gateway 网关绑定到 tailnet IP：</p><ul><li>在 Gateway 网关主机的 <code>~/.opensoul/opensoul.json</code> 中设置 <code>gateway.bind: &quot;tailnet&quot;</code>。</li><li>重启 Gateway 网关 / macOS 菜单栏应用。</li></ul><h3 id="_2-验证发现-可选" tabindex="-1"><a class="header-anchor" href="#_2-验证发现-可选">#</a> 2）验证发现（可选）</h3><p>从 Gateway 网关机器：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _opensoul-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>更多调试说明：<a href="/docs/gateway/bonjour">Bonjour</a>。</p><h4 id="通过-unicast-dns-sd-的-tailnet-维也纳-⇄-伦敦-发现" tabindex="-1"><a class="header-anchor" href="#通过-unicast-dns-sd-的-tailnet-维也纳-⇄-伦敦-发现">#</a> 通过 unicast DNS-SD 的 Tailnet（维也纳 ⇄ 伦敦）发现</h4><p>Android NSD/mDNS 发现无法跨网络。如果你的 Android 节点和 Gateway 网关在不同网络但通过 Tailscale 连接，请改用 Wide-Area Bonjour / unicast DNS-SD：</p><ol><li>在 Gateway 网关主机上设置 DNS-SD 区域（示例 <code>opensoul.internal.</code>）并发布 <code>_opensoul-gw._tcp</code> 记录。</li><li>配置 Tailscale split DNS，将你选择的域指向该 DNS 服务器。</li></ol><p>详情和示例 CoreDNS 配置：<a href="/docs/gateway/bonjour">Bonjour</a>。</p><h3 id="_3-从-android-连接" tabindex="-1"><a class="header-anchor" href="#_3-从-android-连接">#</a> 3）从 Android 连接</h3><p>在 Android 应用中：</p><ul><li>应用通过<strong>前台服务</strong>（持久通知）保持 Gateway 网关连接活动。</li><li>打开<strong>设置</strong>。</li><li>在<strong>发现的 Gateway 网关</strong>下，选择你的 Gateway 网关并点击<strong>连接</strong>。</li><li>如果 mDNS 被阻止，使用<strong>高级 → 手动 Gateway 网关</strong>（主机 + 端口）并<strong>连接（手动）</strong>。</li></ul><p>首次成功配对后，Android 在启动时自动重连：</p><ul><li>手动端点（如果启用），否则</li><li>上次发现的 Gateway 网关（尽力而为）。</li></ul><h3 id="_4-批准配对-cli" tabindex="-1"><a class="header-anchor" href="#_4-批准配对-cli">#</a> 4）批准配对（CLI）</h3><p>在 Gateway 网关机器上：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pending</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>配对详情：<a href="/docs/gateway/pairing">Gateway 网关配对</a>。</p><h3 id="_5-验证节点已连接" tabindex="-1"><a class="header-anchor" href="#_5-验证节点已连接">#</a> 5）验证节点已连接</h3><ul><li>通过节点状态：<div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>通过 Gateway 网关：<div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node.list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --params</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><h3 id="_6-聊天-历史" tabindex="-1"><a class="header-anchor" href="#_6-聊天-历史">#</a> 6）聊天 + 历史</h3><p>Android 节点的 Chat 面板使用 Gateway 网关的<strong>主会话键</strong>（<code>main</code>），因此历史和回复与 WebChat 和其他客户端共享：</p><ul><li>历史：<code>chat.history</code></li><li>发送：<code>chat.send</code></li><li>推送更新（尽力而为）：<code>chat.subscribe</code> → <code>event:&quot;chat&quot;</code></li></ul><h3 id="_7-canvas-摄像头" tabindex="-1"><a class="header-anchor" href="#_7-canvas-摄像头">#</a> 7）Canvas + 摄像头</h3><h4 id="gateway-网关-canvas-主机-推荐用于-web-内容" tabindex="-1"><a class="header-anchor" href="#gateway-网关-canvas-主机-推荐用于-web-内容">#</a> Gateway 网关 Canvas 主机（推荐用于 web 内容）</h4><p>如果你想让节点显示智能体可以在磁盘上编辑的真实 HTML/CSS/JS，请将节点指向 Gateway 网关 canvas 主机。</p><p>注意：节点使用 <code>canvasHost.port</code>（默认 <code>18793</code>）上的独立 canvas 主机。</p><ol><li><p>在 Gateway 网关主机上创建 <code>~/.opensoul/workspace/canvas/index.html</code>。</p></li><li><p>将节点导航到它（局域网）：</p></li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> invoke</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;Android Node&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --command</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> canvas.navigate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --params</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;url&quot;:&quot;http://&lt;gateway-hostname&gt;.local:18793/__opensoul__/canvas/&quot;}&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Tailnet（可选）：如果两个设备都在 Tailscale 上，使用 MagicDNS 名称或 tailnet IP 而不是 <code>.local</code>，例如 <code>http://&lt;gateway-magicdns&gt;:18793/__opensoul__/canvas/</code>。</p><p>此服务器将实时重载客户端注入 HTML 并在文件更改时重新加载。 A2UI 主机位于 <code>http://&lt;gateway-host&gt;:18793/__opensoul__/a2ui/</code>。</p><p>Canvas 命令（仅前台）：</p><ul><li><code>canvas.eval</code>、<code>canvas.snapshot</code>、<code>canvas.navigate</code>（使用 <code>{&quot;url&quot;:&quot;&quot;}</code> 或 <code>{&quot;url&quot;:&quot;/&quot;}</code> 返回默认脚手架）。<code>canvas.snapshot</code> 返回 <code>{ format, base64 }</code>（默认 <code>format=&quot;jpeg&quot;</code>）。</li><li>A2UI：<code>canvas.a2ui.push</code>、<code>canvas.a2ui.reset</code>（<code>canvas.a2ui.pushJSONL</code> 遗留别名）</li></ul><p>摄像头命令（仅前台；权限限制）：</p><ul><li><code>camera.snap</code>（jpg）</li><li><code>camera.clip</code>（mp4）</li></ul><p>参见 <a href="/docs/nodes/camera">Camera 节点</a> 了解参数和 CLI 助手。</p>`,51)])])}const k=s(t,[["render",l]]);export{u as __pageData,k as default};
